transform_js:
transformedData = { data: [], edges: [] };

if (rawData && Array.isArray(rawData.rows)) {
  const nodeMap = new Map();
  const edgeMap = new Map();

  function ensureNode(name) {
    const safeName = String(name || '').trim();
    if (!safeName) {
      return null;
    }
    if (!nodeMap.has(safeName)) {
      nodeMap.set(safeName, { name: safeName, value: 0 });
    }
    return nodeMap.get(safeName);
  }

  rawData.rows.forEach((row) => {
    if (!row || typeof row !== 'object') {
      return;
    }

    const source = String(row.source || '').trim();
    const target = String(row.target || '').trim();
    const value = Number(row.value);
    if (!source || !target || !Number.isFinite(value) || value <= 0) {
      return;
    }

    const sourceNode = ensureNode(source);
    const targetNode = ensureNode(target);
    if (!sourceNode || !targetNode) {
      return;
    }

    sourceNode.value += value;
    targetNode.value += value;

    const edgeKey = `${source}=>${target}`;
    if (!edgeMap.has(edgeKey)) {
      edgeMap.set(edgeKey, { source, target, value: 0 });
    }
    edgeMap.get(edgeKey).value += value;
  });

  transformedData.data = Array.from(nodeMap.values());
  transformedData.edges = Array.from(edgeMap.values());
}

echarts_js:
option = {
  title: {
    text: post.title,
    left: 'center'
  },
  tooltip: {
    trigger: 'item',
    formatter: (params) => {
      if (params.dataType === 'edge') {
        const edge = params.data || {};
        const source = String(edge.source || '');
        const target = String(edge.target || '');
        const value = edge.value ?? params.value ?? 0;
        return `${source} -> ${target}: ${value}`;
      }
      const name = String(params.name || '');
      const value = params.value ?? 0;
      return `${name}: ${value}`;
    }
  },
  series: [
    {
      type: 'chord',
      center: ['50%', '52%'],
      radius: ['70%', '80%'],
      startAngle: 90,
      padAngle: 3,
      minAngle: 1,
      clockwise: true,
      data: transformedData.data || [],
      edges: transformedData.edges || [],
      label: {
        show: true,
        position: 'outside',
        distance: 6
      },
      itemStyle: {
        borderColor: '#ffffff',
